SELECT ticket_id, SUM(file_size) AS total_attachment_size
FROM ticket_attachments
GROUP BY ticket_id;

SELECT report_type, COUNT(*) AS report_count
FROM ticket_reports
GROUP BY report_type;

SELECT tag_name
FROM ticket_tags
WHERE ticket_id = 1;

SELECT DISTINCT t.title
FROM tickets t
INNER JOIN ticket_attachments ta ON t.ticket_id = ta.ticket_id;
